struct Mint
{
	static int m;
	int v;
	Mint(long long value = 0)
	{
		v = value % m;
		if (v < 0)
			v += m;
	}

	static void set_mod(int new_mod) { m = new_mod; }
	friend istream& operator>>(istream& inp, Mint& a)
	{
		ll x;
		inp >> x;
		a = x;
		return inp;
	}
	friend ostream& operator<<(ostream& out, const Mint& a)
	{
		out << a.v;
		return out;
	}

	Mint& operator+=(const Mint& o)
	{
		v += o.v;
		if (v >= m)
			v -= m;
		return *this;
	}
	Mint& operator-=(const Mint& o)
	{
		v -= o.v;
		if (v < 0)
			v += m;
		return *this;
	}
	Mint& operator*=(const Mint& o)
	{
		v = (long long)v * o.v % m;
		return *this;
	}

	Mint pow(long long b) const
	{
		Mint res = 1, a = *this;
		while (b > 0)
		{
			if (b & 1)
				res *= a;
			a *= a;
			b >>= 1;
		}
		return res;
	}

	Mint inv() const
	{
		return pow(m - 2);
	}

	Mint& operator++()
	{
		v++;
		if (v == m)
			v = 0;
		return *this;
	}
	Mint& operator--()
	{
		if (v == 0)
			v = m;
		--v;
		return *this;
	}
	Mint& operator/=(const Mint& other) { return *this *= other.inv(); }

	friend Mint operator+(const Mint& a, const Mint& b) { return Mint(a) += b; }
	friend Mint operator-(const Mint& a, const Mint& b) { return Mint(a) -= b; }
	friend Mint operator*(const Mint& a, const Mint& b) { return Mint(a) *= b; }
	friend Mint operator/(const Mint& a, const Mint& b) { return Mint(a) /= b; }

	friend bool operator==(const Mint& a, const Mint& b) { return a.v == b.v; }
	friend bool operator!=(const Mint& a, const Mint& b) { return a.v != b.v; }

	Mint operator-() const { return Mint(m - v); }
};
int Mint::m = mod;
struct point
{
	int x, y;
	typedef point P;
	point(int x = 0, int y = 0) : x(x), y(y) {};

	friend istream& operator>>(istream& inp, P& a)
	{
		int x1, y1;
		inp >> x1 >> y1;
		a.x = x1;
		a.y = y1;
		return inp;
	}

	friend ostream& operator<<(ostream& output, const P& p)
	{
		output << p.x << " " << p.y;
		return output;
	}

	P operator+(const P o) const
	{
		return P(x + o.x, y + o.y);
	}

	P operator-(const P o) const
	{
		return P(x - o.x, y - o.y);
	}

	P& operator+=(const point& o)
	{
		x += o.x;
		y += o.y;
		return *this;
	}

	P& operator-=(const point& o)
	{
		x -= o.x;
		y -= o.y;
		return *this;
	}

	bool operator==(const P o) const
	{
		return { x == o.x && y == o.y };
	}

	bool operator!=(const P o) const
	{
		return !(*this == o);
	}

	bool operator<(const P o) const
	{
		return x < o.x || (x == o.x && y < o.y);
	}

	bool operator<=(const P o) const
	{
		return (*this < o || *this == o);
	}

	bool operator>(const P o) const
	{
		return !(*this <= o);
	}

	bool operator>=(const P o) const
	{
		return !(*this < o);
	}

	ll dot(const P o) const
	{
		return (1ll * x * o.x + 1ll * y * o.y);
	}

	ll cross(const P o) const
	{
		return (1ll * x * o.y - 1ll * y * o.x);
	}

	ll len2() const
	{
		return (1ll * x * x + 1ll * y * y);
	}

	ld len() const
	{
		return sqrtl(1ll * x * x + 1ll * y * y);
	}

	ld dist(const P o) const
	{
		return (o - *this).len();
	}

	ll dist2(const P o) const
	{
		return (o - *this).len2();
	}

	P operator*(const int k)
	{
		P b = *this;
		b.x *= k;
		b.y *= k;
		return b;
	}

	P& operator*=(const int k)
	{
		(*this).x *= k;
		(*this).y *= k;
		return (*this);
	}

	P reflect(P x)
	{
		point h = x - *this;
		h *= 2;
		return (*this) + h;
	}
};
struct circle
{
	point p;
	int r;

	circle(point p = { 0, 0 }, int r = 0) : p(p), r(r) {};

	friend istream& operator>>(istream& in, circle& c)
	{
		in >> c.p >> c.r;
		return in;
	}

	friend std::ostream& operator<<(std::ostream& out, const circle& c)
	{
		out << c.p << " " << c.r;
		return out;
	}

	bool tg(const circle o) const
	{
		ll d2 = p.dist2(o.p);
		if (d2 == 1ll * (r + o.r) * (r + o.r))
			return true;
		else
			return false;
	}
};


